#include <iostream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int qx, qy, px, py;
    cin >> qx >> qy >> px >> py;

    if (qx == px || qy == py || abs(qx - px) == abs(qy - py)) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }

    return 0;
}
